query:
-- Total animals
SELECT COUNT(*) as total_animals FROM animals WHERE deleted_at IS NULL;

-- Active vs inactive
SELECT is_active, COUNT(*) as count FROM animals WHERE deleted_at IS NULL GROUP BY is_active;

-- By acquisition type
SELECT acquisition_type, COUNT(*) as count FROM animals WHERE deleted_at IS NULL GROUP BY acquisition_type;

-- By species
SELECT sp.name as species, COUNT(*) as count 
FROM animals a 
JOIN species sp ON a.species_id = sp.id 
WHERE a.deleted_at IS NULL 
GROUP BY sp.name ORDER BY count DESC;

